let name = "Alice";
const age = 25;
let isStudent = true;

console.log("Name:", name);
console.log("Age:", age);
console.log("Is Student:", isStudent);

// Changing value of let
name = "Bob";
console.log("New Name:", name);

// Cannot change const
// age = 26; // This would cause an error!

// Different data types
let score = 95.5;        // Number
let message = "Great!"; // String
let isActive = false;   // Boolean
let nothing = null;      // Null
let notDefined;          // Undefined
let person = {           // Object
  firstName: "John",
  lastName: "Doe"
};
let fruits = ["apple", "banana", "orange"]; // Array

console.log("\\nScore:", score);
console.log("Message:", message);
console.log("Is Active:", isActive);
console.log("Nothing:", nothing);
console.log("Not Defined:", notDefined);
console.log("Person:", person);
console.log("Fruits:", fruits);

// Type checking
console.log("\\nTypes:");
console.log(typeof name);      // string
console.log(typeof score);     // number
console.log(typeof isStudent); // boolean
console.log(typeof person);    // object
console.log(typeof fruits);    // object (arrays are objects)`,"data-matrix-id":"src/chapters/Chapter4.tsx:156:10","data-matrix-name":"InteractiveCodeEditor","data-component-path":"src/chapters/Chapter4.tsx","data-component-line":"156","data-component-file":"Chapter4.tsx","data-component-name":"InteractiveCodeEditor","data-component-content":"%7B%22title%22%3A%22Variables%20Demo%22%2C%22language%22%3A%22javascript%22%2C%22initialCode%22%3A%22%5BTemplateLiteral%5D%22%7D"}),a.jsx(_,{questions:[{question:"Which keyword should you use to declare a constant that won't change?",options:["var","let","const","static"],correctAnswer:2,explanation:"const declares a constant that cannot be reassigned after initialization."},{question:"What is the typeof [] (empty array)?",options:["array","object","undefined","null"],correctAnswer:1,explanation:"In JavaScript, arrays are technically objects, so typeof [] returns 'object'."}],"data-matrix-id":"src/chapters/Chapter4.tsx:204:10","data-matrix-name":"Quiz","data-component-path":"src/chapters/Chapter4.tsx","data-component-line":"204","data-component-file":"Chapter4.tsx","data-component-name":"Quiz","data-component-content":"%7B%22questions%22%3A%5B%22%5BObjectExpression%5D%22%2C%22%5BObjectExpression%5D%22%5D%7D"}),a.jsx(q,{question:"Create a JavaScript program that declares variables for your name (const), your age (let), and whether you're a student (boolean). Then print all three values to the console with their data types.",hint:"Use const for name (won't change), let for age (might change), and console.log() with typeof to check data types.",solution:`const name = "John Doe";
let age = 25;
let isStudent = true;

