const title = document.getElementById("title");
const items = document.getElementsByClassName("item");
const paragraphs = document.getElementsByTagName("p");
const firstButton = document.querySelector("button");
const allButtons = document.querySelectorAll("button");

// Changing Content
title.textContent = "New Title";
title.innerHTML = "<span>HTML Content</span>";

// Changing Styles
title.style.color = "blue";
title.style.fontSize = "24px";
title.classList.add("active");
title.classList.remove("hidden");
title.classList.toggle("highlight");

// Creating Elements
const newDiv = document.createElement("div");
newDiv.textContent = "I'm a new div!";
newDiv.className = "container";
document.body.appendChild(newDiv);

// Removing Elements
const toRemove = document.querySelector(".obsolete");
toRemove.remove();

// Event Handling
const button = document.querySelector("#myButton");
button.addEventListener("click", function() {
    alert("Button clicked!");
});

button.addEventListener("mouseover", () => {
    button.style.backgroundColor = "red";
});

button.addEventListener("mouseout", () => {
    button.style.backgroundColor = "blue";
});`,"data-matrix-id":"src/chapters/Chapter5.tsx:77:10","data-matrix-name":"InteractiveCodeEditor","data-component-path":"src/chapters/Chapter5.tsx","data-component-line":"77","data-component-file":"Chapter5.tsx","data-component-name":"InteractiveCodeEditor","data-component-content":"%7B%22title%22%3A%22DOM%20Manipulation%20Demo%22%2C%22language%22%3A%22javascript%22%2C%22initialCode%22%3A%22%5BTemplateLiteral%5D%22%7D"}),a.jsx(_,{questions:[{question:"Which method selects all elements matching a CSS selector?",options:["getElementById()","getElementsByClassName()","querySelector()","querySelectorAll()"],correctAnswer:3,explanation:"querySelectorAll() returns a NodeList of all elements matching the specified CSS selector."},{question:"What is the correct way to add a class to an element?",options:["element.class = 'active'","element.className = 'active'","element.classList.add('active')","element.addClass('active')"],correctAnswer:2,explanation:"classList.add() is the modern way to add classes. className is a string that would overwrite all classes."}],"data-matrix-id":"src/chapters/Chapter5.tsx:123:10","data-matrix-name":"Quiz","data-component-path":"src/chapters/Chapter5.tsx","data-component-line":"123","data-component-file":"Chapter5.tsx","data-component-name":"Quiz","data-component-content":"%7B%22questions%22%3A%5B%22%5BObjectExpression%5D%22%2C%22%5BObjectExpression%5D%22%5D%7D"}),a.jsx(q,{question:"Create a JavaScript program that: 1) Selects a div with id 'container', 2) Changes its background color to blue, 3) Creates a new paragraph element with text 'Hello DOM!', 4) Appends the paragraph to the container, 5) Adds a click event listener to the paragraph that removes it when clicked.",hint:"Use document.createElement() to create elements, appendChild() to add them, and addEventListener() for events",solution:`// Select the container
const container = document.getElementById('container');

// Change background color
container.style.backgroundColor = 'blue';

// Create a new paragraph
const paragraph = document.createElement('p');
paragraph.textContent = 'Hello DOM!';

// Append to container
container.appendChild(paragraph);

// Add click event to remove the paragraph
paragraph.addEventListener('click', function() {
    this.remove(); // or container.removeChild(this)
    console.log('Paragraph removed!');
});

// Alternative: using textContent vs innerHTML
// paragraph.innerHTML = '<strong>Bold Text</strong>';`,"data-matrix-id":"src/chapters/Chapter5.tsx:140:10","data-matrix-name":"Exercise","data-component-path":"src/chapters/Chapter5.tsx","data-component-line":"140","data-component-file":"Chapter5.tsx","data-component-name":"Exercise","data-component-content":"%7B%22question%22%3A%22Create%20a%20JavaScript%20program%20that%3A%201)%20Selects%20a%20div%20with%20id%20'container'%2C%202)%20Changes%20its%20background%20color%20to%20blue%2C%203)%20Creates%20a%20new%20paragraph%20element%20with%20text%20'Hello%20DOM!'%2C%204)%20Appends%20the%20paragraph%20to%20the%20container%2C%205)%20Adds%20a%20click%20event%20listener%20to%20the%20paragraph%20that%20removes%20it%20when%20clicked.%22%2C%22hint%22%3A%22Use%20document.createElement()%20to%20create%20elements%2C%20appendChild()%20to%20add%20them%2C%20and%20addEventListener()%20for%20events%22%2C%22solution%22%3A%22%5BTemplateLiteral%5D%22%7D"})]})},"advjs-events":{id:"advjs-events",title:"Events and Event Handling",icon:a.jsx(g2,{className:"w-5 h-5","data-matrix-id":"src/chapters/Chapter5.tsx:172:12","data-matrix-name":"MousePointer","data-component-path":"src/chapters/Chapter5.tsx","data-component-line":"172","data-component-file":"Chapter5.tsx","data-component-name":"MousePointer","data-component-content":"%7B%22className%22%3A%22w-5%20h-5%22%7D"}),content:a.jsxs("div",{className:"space-y-6","data-matrix-id":"src/chapters/Chapter5.tsx:174:8","data-matrix-name":"div","data-component-path":"src/chapters/Chapter5.tsx","data-component-line":"174","data-component-file":"Chapter5.tsx","data-component-name":"div","data-component-content":"%7B%22className%22%3A%22space-y-6%22%7D",children:[a.jsxs("div",{className:"prose dark:prose-invert max-w-none","data-matrix-id":"src/chapters/Chapter5.tsx:175:10","data-matrix-name":"div","data-component-path":"src/chapters/Chapter5.tsx","data-component-line":"175","data-component-file":"Chapter5.tsx","data-component-name":"div","data-componen